import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";

function Result() {
  const navigate = useNavigate();
  const { state } = useLocation();

  const {
    gem_prediction = "Unknown",
    gem_confidence = 0,
    shape_prediction = "",
    shape_confidence = 0,
    image,
    show_shape = false,
  } = state || {};

  const gemConf = (gem_confidence * 100).toFixed(1);
  const shapeConf = (shape_confidence * 100).toFixed(1);

  return (
    <>
      <Topnav />

      <main className="min-h-screen bg-[#0a1425] text-white flex flex-col items-center justify-center py-12 px-6">
        <div className="w-full max-w-4xl text-center">
          <h1 className="text-6xl md:text-8xl font-extrabold mb-10 tracking-tight text-[#60a5fa]">
            {gem_prediction}
          </h1>

          {image && (
            <div className="flex justify-center mb-12">
              <div className="w-80 md:w-[500px] aspect-square rounded-3xl overflow-hidden shadow-2xl shadow-black/70 border-4 border-[#1e40af]/40">
                <img src={URL.createObjectURL(image)} alt={gem_prediction} className="w-full h-full object-cover" />
              </div>
            </div>
          )}

          <div className="space-y-12 max-w-2xl mx-auto">
            <div>
              <div className="text-xl text-slate-400 mb-3">Gem Identification</div>
              <div className="text-4xl font-semibold mb-4">{gem_prediction}</div>
              <div className="inline-block px-8 py-4 bg-[#1e40af]/70 rounded-full text-[#60a5fa] font-medium text-xl shadow-md">
                Confidence: {gemConf}%
              </div>
            </div>

            {show_shape && shape_prediction && (
              <div>
                <div className="text-xl text-slate-400 mb-3">Shape / Cut</div>
                <div className="text-4xl font-semibold mb-4 capitalize">{shape_prediction}</div>
                <div className="inline-block px-8 py-4 bg-[#1e40af]/70 rounded-full text-[#60a5fa] font-medium text-xl shadow-md">
                  Confidence: {shapeConf}%
                </div>
              </div>
            )}
          </div>

          <button
            onClick={() => navigate("/imageuploader")}
            className="mt-16 px-12 py-6 bg-[#3b82f6] hover:bg-[#2563eb] text-white text-2xl font-semibold rounded-full shadow-2xl shadow-[#3b82f6]/40 hover:shadow-3xl hover:shadow-[#3b82f6]/60 transition-all hover:scale-105"
          >
            Re-Analyze Another Gem
          </button>
        </div>
      </main>

      <Footer />
    </>
  );
}

export default Result;
